import React from "react";
import { useParams } from "react-router-dom";
import "./Gallery.css";

function ArtistGallery({ cart, setCart }) {
  const { id } = useParams();

  const artworks = [
    { id: 1, title: "Peinture 1", artist: "alice", size: "50x70 cm", price: 120, img: "/img/art1.jpg" },
    { id: 2, title: "Sculpture 1", artist: "bob", size: "30x40 cm", price: 200, img: "/img/art2.jpg" },
    { id: 3, title: "Dessin 1", artist: "claire", size: "20x30 cm", price: 80, img: "/img/art3.jpg" },
    { id: 4, title: "Peinture 2", artist: "alice", size: "60x80 cm", price: 150, img: "/img/art4.jpg" },
  ];

  const artistArtworks = artworks.filter((art) => art.artist === id);

  return (
    <div className="gallery-container">
      <h2>Œuvres de {id.charAt(0).toUpperCase() + id.slice(1)}</h2>
      <div className="gallery-grid">
        {artistArtworks.map((art) => (
          <div key={art.id} className="art-card visible">
            <img src={art.img} alt={art.title} />
            <h3>{art.title}</h3>
            <p className="size">{art.size}</p>
            <p className="price">{art.price} €</p>
            <button onClick={() => setCart([...cart, art])}>Ajouter au panier</button>
          </div>
        ))}
      </div>
    </div>
  );
}

export default ArtistGallery;
